long long allocateBooks(vector<long long>& books, int N, int M) {
    if (M > N) return -1;

    long long low = 0, high = 0;
    for (auto pages : books) {
        low = max(low, pages);
        high += pages;
    }

    auto isPossible = [&](long long limit) {
        int count = 1;
        long long sum = 0;
        for (auto p : books) {
            if (p > limit) return false;
            if (sum + p > limit) {
                count++;
                sum = p;
                if (count > M) return false;
            } else sum += p;
        }
        return true;
    };

    long long ans = -1;
    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (isPossible(mid)) {
            ans = mid;
            high = mid - 1;
        } else low = mid + 1;
    }
    return ans;
}

