public static long allocateBooks(long[] books, int N, int M) {
    if (M > N) return -1;

    long low = 0, high = 0;
    for (long b : books) {
        low = Math.max(low, b);
        high += b;
    }

    long result = -1;
    while (low <= high) {
        long mid = low + (high - low) / 2;
        if (isPossible(books, N, M, mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return result;
}

private static boolean isPossible(long[] books, int N, int M, long limit) {
    int count = 1;
    long sum = 0;
    for (int i = 0; i < N; i++) {
        if (books[i] > limit) return false;
        if (sum + books[i] > limit) {
            count++;
            sum = books[i];
            if (count > M) return false;
        } else {
            sum += books[i];
        }
    }
    return true;
}

