function allocateBooks(books, N, M) {
    if (M > N) return -1;

    let low = Math.max(...books);
    let high = books.reduce((a, b) => a + b, 0);

    const isPossible = (limit) => {
        let count = 1, sum = 0;
        for (let b of books) {
            if (b > limit) return false;
            if (sum + b > limit) {
                count++;
                sum = b;
                if (count > M) return false;
            } else sum += b;
        }
        return true;
    };

    let result = -1;
    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (isPossible(mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return result;
}
